	, REGISTER_IP /*등록자_아이피*/
	, REGISTRATION_DT /*등록_일시*/
	, UPDATER_SEQ /*수정자_시퀀스*/
	, UPDATER_IP /*수정자_아이피*/
	, UPDATE_DT /*수정_일시*/
) VALUES (
	  #{registerSeq}
	, #{requestMethodCd}
	, #{requestUrl}
	, #{executionTime}
	, TRUE
	, #{registerSeq}
